// src/components/Chatbot.js
import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000"; // Your Flask Backend URL

// Style constants
const chatContainerStyle = {
  maxWidth: "600px",
  margin: "auto",
  border: "1px solid #ccc",
  borderRadius: "10px",
  display: "flex",
  flexDirection: "column",
  height: "600px",
  overflow: "hidden",
};

const messagesContainerStyle = {
  flexGrow: 1,
  overflowY: "auto",
  padding: "20px",
  backgroundColor: "#f9f9f9",
};

const inputAreaStyle = {
  display: "flex",
  padding: "10px",
  borderTop: "1px solid #ccc",
  backgroundColor: "#fff",
};

const botMessageStyle = {
  padding: "10px 15px",
  backgroundColor: "#e7f3ff",
  borderRadius: "15px",
  marginBottom: "10px",
  maxWidth: "80%",
  alignSelf: "flex-start",
  wordWrap: "break-word",
};

const userMessageStyle = {
  padding: "10px 15px",
  backgroundColor: "#d1e7c4",
  borderRadius: "15px",
  marginBottom: "10px",
  maxWidth: "80%",
  alignSelf: "flex-end",
  wordWrap: "break-word",
  marginLeft: "auto",
};

function Chatbot() {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello! I am the AI Project Demonstration Assistant. Ask me anything about the Deepfake Detection System project—its models, technologies, or goals!",
    },
  ]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input;
    setInput("");
    setIsLoading(true);

    // 1. Add user message to display
    setMessages((prev) => [...prev, { sender: "user", text: userMessage }]);

    try {
      // 2. Call the Chatbot endpoint
      const response = await axios.post(
        `${API_URL}/chat`,
        { message: userMessage },
        {
          headers: { "Content-Type": "application/json" },
        }
      );

      const botResponse =
        response.data.response ||
        "Sorry, I couldn't get a response from the AI.";

      // 3. Add bot response to display
      setMessages((prev) => [...prev, { sender: "bot", text: botResponse }]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        {
          sender: "bot",
          text: "Error connecting to the server. Check your backend terminal for errors.",
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      sendMessage();
    }
  };

  return (
    <div>
      <h2>🤖 Project Chatbot Assistant</h2>
      <div style={chatContainerStyle}>
        <div style={messagesContainerStyle}>
          {messages.map((msg, index) => (
            <div
              key={index}
              style={msg.sender === "user" ? userMessageStyle : botMessageStyle}
            >
              <strong>{msg.sender === "user" ? "You" : "Bot"}:</strong>{" "}
              {msg.text}
            </div>
          ))}
          {isLoading && (
            <div style={botMessageStyle}>
              <strong>Bot:</strong> Thinking...
            </div>
          )}
        </div>

        <div style={inputAreaStyle}>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask about the project's models or technology..."
            disabled={isLoading}
            style={{
              flexGrow: 1,
              padding: "10px",
              border: "1px solid #ddd",
              borderRadius: "5px",
              marginRight: "10px",
            }}
          />
          <button
            onClick={sendMessage}
            disabled={isLoading || !input.trim()}
            style={{
              padding: "10px 15px",
              backgroundColor: "#3498db",
              color: "white",
              border: "none",
              borderRadius: "5px",
              cursor: "pointer",
              opacity: isLoading || !input.trim() ? 0.6 : 1,
            }}
          >
            Send
          </button>
        </div>
      </div>
    </div>
  );
}

export default Chatbot;
